import UIKit

class AppDelegate: UIResponder, UIApplicationDelegate {

    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        if let components = URLComponents(url: url, resolvingAgainstBaseURL: false), 
           components.scheme == "https", 
           components.host == "myapp.com", 
           let queryItems = components.queryItems,
           let token = queryItems.first(where: { $0.name == "token" })?.value {
            let storyboard = UIStoryboard(name: "Main", bundle: nil)
            if let resetPasswordVC = storyboard.instantiateViewController(withIdentifier: "ResetPasswordViewController") as? ResetPasswordViewController {
                resetPasswordVC.token = token
                if let windowScene = (app.connectedScenes.first as? UIWindowScene),
                   let sceneDelegate = windowScene.delegate as? SceneDelegate,
                   let window = sceneDelegate.window {
                    window.rootViewController?.present(resetPasswordVC, animated: true, completion: nil)
                }
            }
        }
        return false
    }
}

class SceneDelegate: UIResponder, UIWindowSceneDelegate {

    var window: UIWindow?

    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let _ = (scene as? UIWindowScene) else { return }
